# ASP.NET Framework → ASP.NET Core (.NET 8) Migration
# ====================================================

## Pattern Inventory

1. Response.End()              → Remove; return IActionResult instead
2. Response.Redirect(url,true) → Return RedirectResult
3. catch(ThreadAbortException) → Remove entirely (never thrown in .NET 8)
4. WebForms event handlers     → MVC action methods returning IActionResult

## Migrated Code

```csharp
// ReportController.cs — ASP.NET Core (.NET 8)
using Microsoft.AspNetCore.Mvc;
using System.Text;

public class ReportController : Controller
{
    // Was: btnExport_Click with Response.Write + Response.End()
    // Now: Return a FileResult — the framework handles the response lifecycle.
    [HttpPost]
    public IActionResult Export()
    {
        var data = GenerateReport();

        // File() sets Content-Type and Content-Disposition automatically.
        // No Response.Clear/Write/End needed — returning ends the action.
        return File(
            Encoding.UTF8.GetBytes(data),
            "text/csv",
            "report.csv"
        );
    }

    // Was: btnRedirect_Click with Response.Redirect(url, true)
    // Now: Return RedirectResult — no Thread.Abort, no ThreadAbortException.
    [HttpPost]
    public IActionResult ProcessAction()
    {
        if (!User.Identity?.IsAuthenticated ?? true)
        {
            // Just return — no endResponse parameter, no abort.
            return Redirect("/login");
        }

        try
        {
            ProcessRequest();
            return Redirect("/success");
        }
        // ThreadAbortException catch block is REMOVED — it is never thrown
        // in .NET 6+. Catching it would be dead code.
        catch (Exception ex)
        {
            LogError(ex);
            return Redirect("/error");
        }
    }

    private string GenerateReport() => /* ... */ "";
    private void ProcessRequest() { /* ... */ }
    private void LogError(Exception ex) { /* ... */ }
}
```

